import axios from 'axios';

const api = axios.create({
  baseURL: 'https://ecennale-electricien-backend.ddev.site/api',
  headers: {
    'Content-Type': 'application/json',
  },
});

api.interceptors.request.use(
  (config) => {
    const apiKey = localStorage.getItem('admin_apiKey');
    if (apiKey) {
      config.headers.Authorization = `Bearer ${apiKey}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('admin_role');
      localStorage.removeItem('admin_email');
      localStorage.removeItem('admin_apiKey');
      window.location.href = '/login';
    }
    const message = error.response?.data?.error || error.response?.data?.message || error.message || 'Une erreur est survenue';
    return Promise.reject(new Error(message));
  }
);

export default api;
